define('taoQtiTest/controller/creator/views/translation',['jquery', 'uikitLoader', 'taoQtiTest/controller/creator/templates/index'], function ($, ui, templates) {
  'use strict';
  function translationView(creatorContext) {
    var modelOverseer = creatorContext.getModelOverseer();
    var config = modelOverseer.getConfig();
    if (!config.translation) {
      return;
    }
    var $container = $('.test-creator-props');
    var template = templates.properties.translation;
    var $view = $(template(config)).appendTo($container);
    ui.startDomComponent($view);
    $view.on('change', '[name="translationStatus"]', e => {
      var input = e.target;
      config.translationStatus = input.value;
    });
  }
  return translationView;
});
