define('taoQtiTest/controller/creator/helpers/validators',['ui/validator/validators', 'jquery', 'lodash', 'i18n', 'taoQtiTest/controller/creator/helpers/outcome', 'taoQtiTest/controller/creator/helpers/qtiElement', 'taoQtiItem/qtiCreator/widgets/helpers/qtiIdentifier'], function (validators, $, _, __, outcomeHelper, qtiElementHelper, qtiIdentifier) {
  'use strict';

  var qtiIdPattern = qtiIdentifier.pattern;
  var qtiTypesForUniqueIds = ['assessmentTest', 'testPart', 'assessmentSection', 'assessmentItemRef'];
  function idFormatValidator() {
    return {
      name: 'idFormat',
      message: qtiIdentifier.invalidQtiIdMessage,
      validate: function validate(value, callback) {
        if (typeof callback === 'function') {
          callback(qtiIdPattern.test(value));
        }
      }
    };
  }
  function testidFormatValidator() {
    var qtiTestIdPattern = /^\S+$/;
    return {
      name: 'testIdFormat',
      message: __('is not a valid identifier (everything except spaces)'),
      validate: function validate(value, callback) {
        if (typeof callback === 'function') {
          callback(qtiTestIdPattern.test(value));
        }
      }
    };
  }
  function idAvailableValidator(modelOverseer) {
    return {
      name: 'testIdAvailable',
      message: __('is already used in the test.'),
      validate: function validate(value, callback, options) {
        if (options.identifier) {
          var key = value.toUpperCase();
          var identifiers = extractIdentifiers(modelOverseer.getModel(), qtiTypesForUniqueIds);
          var $idInUI = $("[id=\"props-".concat(options.identifier, "\"]:contains(\"").concat(value, "\")"));
          if (typeof callback === 'function') {
            var counts = _.countBy(identifiers, 'identifier');
            callback(typeof counts[key] === 'undefined' || $idInUI.length === 1 && $idInUI.text() === value && counts[key] === 1);
          }
        } else {
          throw new Error('missing required option "identifier"');
        }
      }
    };
  }
  function registerValidators(modelOverseer) {
    validators.register('idFormat', idFormatValidator());
    validators.register('testIdFormat', testidFormatValidator());
    validators.register('testIdAvailable', idAvailableValidator(modelOverseer), true);
  }
  function validateModel(model) {
    var identifiers = extractIdentifiers(model, qtiTypesForUniqueIds);
    var nonUniqueIdentifiers = 0;
    var outcomes = _.keyBy(outcomeHelper.listOutcomes(model));
    var messageDetails = '';
    _(identifiers).countBy('identifier').forEach(function (count, id) {
      if (count > 1) {
        nonUniqueIdentifiers++;
        messageDetails += "\n".concat(id);
      }
    });
    if (nonUniqueIdentifiers >= 1) {
      throw new Error(__('The following identifiers are not unique accross the test : %s', messageDetails));
    }
    _.forEach(model.testParts, function (testPart) {
      _.forEach(testPart.assessmentSections, function (assessmentSection) {
        _.forEach(assessmentSection.rubricBlocks, function (rubricBlock) {
          var feedbackBlock = qtiElementHelper.lookupElement(rubricBlock, 'rubricBlock.div.feedbackBlock', 'content');
          if (feedbackBlock && !outcomes[feedbackBlock.outcomeIdentifier]) {
            throw new Error(__('The outcome "%s" does not exist, but it is referenced by a feedback block!', feedbackBlock.outcomeIdentifier));
          }
        });
      });
    });
  }
  function extractIdentifiers(model, includesOnlyTypes, excludeTypes) {
    var identifiers = [];
    var extract = function extract(element) {
      if (element && _.has(element, 'identifier') && _.isString(element.identifier)) {
        if (!includesOnlyTypes.length || _.includes(includesOnlyTypes, element['qti-type'])) {
          identifiers.push({
            identifier: element.identifier.toUpperCase(),
            originalIdentifier: element.identifier,
            type: element['qti-type'],
            label: element.title || element.identifier
          });
        }
      }
      _.forEach(element, function (subElement) {
        if (_.isPlainObject(subElement) || _.isArray(subElement)) {
          if (!excludeTypes.length || !_.includes(excludeTypes, subElement['qti-type'])) {
            extract(subElement);
          }
        }
      });
    };
    if (_.isPlainObject(model) || _.isArray(model)) {
      excludeTypes = excludeTypes || [];
      includesOnlyTypes = includesOnlyTypes || [];
      extract(model);
    }
    return identifiers;
  }
  function checkIfItemIdValid(value, modelOverseer) {
    var identifiers = extractIdentifiers(modelOverseer.getModel(), qtiTypesForUniqueIds);
    var key = value.toUpperCase();
    var counts = _.countBy(identifiers, 'identifier');
    return qtiIdPattern.test(value) && counts[key] === 1;
  }
  return {
    qtiTypesForUniqueIds,
    extractIdentifiers,
    registerValidators,
    validateModel,
    checkIfItemIdValid
  };
});
